const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x102018);this.hpP=20;this.hpE=20;this.ui=this.add.text(10,10,'P:20 E:20');['공격','방어','회복'].forEach((k,i)=>{const b=this.add.rectangle(90+i*120,H-70,100,44,0x7c3aed).setInteractive();this.add.text(90+i*120,H-78,k,{fontSize:'18px'}).setOrigin(.5);b.on('pointerdown',()=>this.turn(i));});this.r=this.input.keyboard.addKey('R');}turn(i){if(this.over)return; if(i===0)this.hpE-=Phaser.Math.Between(3,6); if(i===1)this.hpP+=1; if(i===2)this.hpP+=Phaser.Math.Between(2,4); const e=Phaser.Math.Between(0,2); if(e===0)this.hpP-=Phaser.Math.Between(2,5); if(e===2)this.hpE+=1; this.hpP=Math.min(25,this.hpP); this.hpE=Math.min(25,this.hpE); this.ui.setText(`P:${this.hpP} E:${this.hpE}`); if(this.hpP<=0||this.hpE<=0){this.over=true;this.add.text(W/2,H/2,this.hpP>0?'WIN\nR':'LOSE\nR',{align:'center'}).setOrigin(.5);} }update(){if(this.r.isDown)this.scene.restart();}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,scene:[S]});
